    DataResult result;
    result.data_type = data_type;

    stream >> result.data_type;

    uint32_t item_count = 0;
    stream >> item_count;

    if (data_type == 0) {
        result.int_items.reserve(item_count);
        for(uint32_t i = 0; i < item_count; ++i) {
            uint32_t value;
            stream >> value;
            result.int_items.emplace_back(value);
