#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <span>
#include <stdexcept>

struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    // Create a buffer_adaptor from the input buffer
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);

    // Preview the first byte (data_type) without advancing the read pointer
    uint8_t data_type;
    adaptor.copy(&data_type);

    // Calculate the total size needed for reading
    uint32_t item_count = 0; // We'll read this next
    size_t total_size_needed = 0;

    // Check if the buffer has enough data using buffer_adaptor's size function
    if (adaptor.size() < 1) {
        throw std::runtime_error("Buffer too small to read data_type");
    }

    // Read the actual data_type and item_count
    uint32_t item_count_value;
    adaptor.read(&data_type);  // This advances the read pointer
    adaptor.read(&item_count_value);

    // Calculate the total size needed after reading item_count
    total_size_needed = 1 + 4 + (item_count_value * (data_type == 0 ? sizeof(uint32_t) : sizeof(float)));

    // Check if the buffer has enough data for all items
    if (adaptor.size() < (item_count_value * (data_type == 0 ? sizeof(uint32_t) : sizeof(float)))) {
        throw std::runtime_error("Insufficient data in buffer for requested items");
    }

    // Read the items based on data_type
    if (data_type == 0) {
        // Read integers
        std::vector<uint32_t> int_items(item_count_value);
        adaptor.read(int_items.data(), item_count_value * sizeof(uint32_t));
        return DataResult{data_type, std::move(int_items), {}};
    } else {
        // Read floats
        std::vector<float> float_items(item_count_value);
        adaptor.read(float_items.data(), item_count_value * sizeof(float));
        return DataResult{data_type, {}, std::move(float_items)};
    }
}
