bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    hexi::buffer_adaptor adaptor(buffer, hexi::init_empty);

    // Check available space using free()
    size_t required_space = sizeof(uint32_t) + sizeof(uint32_t) + items.size() * sizeof(uint32_t);
    if (adaptor.free() < required_space) {
        return false;
