template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator instance
    hexi::block_allocator<int, element_count> allocator;

    std::cout << "Demonstrating block_allocator free list management:" << std::endl;
    std::cout << "Initial state: Free list is empty" << std::endl;

    // First allocation - calls allocate() which internally calls pop()
    int* obj1 = allocator.allocate();
    std::cout << "Allocated first object. Free list now has " << element_count - 1 << " slots remaining" << std::endl;

    // Second allocation - calls allocate() again
    int* obj2 = allocator.allocate();
    std::cout << "Allocated second object. Free list now has " << element_count - 2 << " slots remaining" << std::endl;

    // Deallocate first object - calls deallocate() which internally calls push()
    allocator.deallocate(obj1);
    std::cout << "Deallocated first object. Free list now has " << element_count - 1 << " slots available" << std::endl;

    // Deallocate second object
    allocator.deallocate(obj2);
    std::cout << "Deallocated second object. Free list is now full with " << element_count << " slots" << std::endl;

    // Demonstrate circular linked list behavior
    std::cout << "\nTesting circular linked list behavior:" << std::endl;

    // Third allocation - should use the pre-allocated block from free list
    int* obj3 = allocator.allocate();
    std::cout << "Allocated third object from existing free list" << std::endl;

    // Fourth allocation - should use the same block until it's exhausted
    int* obj4 = allocator.allocate();
    std::cout << "Allocated fourth object from existing free list" << std::endl;

    // Deallocate both objects
    allocator.deallocate(obj3);
    allocator.deallocate(obj4);
    std::cout << "Both objects deallocated. Free list restored" << std::endl;

    // Final allocation - demonstrates the complete cycle
    int* final_obj = allocator.allocate();
    std::cout << "Final allocation completed the free list cycle" << std::endl;

    // Cleanup
    allocator.deallocate(final_obj);
    std::cout << "All objects deallocated. Block_allocator demonstration complete." << std::endl;
}
```

