        adaptor << sensor_id;

        for (const auto& temp : temperatures) {
            const auto converted = hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(temp);
            adaptor << converted;
        }

        const auto converted_pressure = hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(pressure);
        adaptor << converted_pressure;
    }

    void serialise(auto& adaptor) {
        // Deserialization: convert from little-endian to native
        adaptor >> sensor_id;

        for (auto& temp : temperatures) {
            adaptor >> temp;
            hexi::endian::little_to_native_inplace(temp);
        }

        adaptor >> pressure;
        hexi::endian::little_to_native_inplace(pressure);
    }
};

